module.exports = async function(data) {
    const payload = data.$trigger?.payload || {};
    const keys    = data.$trigger?.keys || [];

    const isManual = ('rating' in payload) && !('rating_updated_at' in payload);

    if (!isManual || !keys.length) {
        throw new Error('skip: not a manual rating change');
    }

    return { userIds: keys, ts: Date.now() };
};

module.exports = async function(data) {
    // 1. Grab the single player object directly
    const player = data.$trigger;
    const user = data.read_user;

    const playerTs = Number(player?.ratingUpdatedAt || 0);
    const userTs   = Number(user?.rating_updated_at || 0);

    const shouldUpdate = playerTs > userTs

    if (!shouldUpdate) throw('Skip rating update')

    // 2. Safety check: make sure the userId actually exists before proceeding
    if (!player || !player.userId) {
        return null; // Return null (or {}) if data is missing to prevent errors
    }

    // 3. Get today's date in YYYY-MM-DD format
    const today = new Date().toISOString().split('T')[0];

    // 4. Return the newly formatted object
    return {
        player_day: `${player.userId}@${today}`,
        player: player.userId,
        day: today,
        wins: player.wins || 0,
        losses: player.losses || 0,
        rating: player.rating || 1500
    };
}

module.exports = async function(data) {
	// Do something...
    const { email } = data.$trigger.payload

	const index = email.indexOf('@');

    // 2. Fast pseudo-random 3-character generator (bypasses heavy Math.random object allocation)
    const rand = (Date.now() ^ Math.floor(Math.random() * 0x100000)).toString(36).slice(-3);

    // 3. Extract and concatenate in one step
    return `${email.substring(0, index)}#${rand}`;
}

module.exports = async function(data) {
    const mm = data.$trigger?.payload?.appState?.matchmaking;
    if (!mm?.players || !mm?.completedMatches) return [];

    const { players, completedMatches } = mm;
    const result = [];

    const matchPayloads = {};
    for (const match of completedMatches) {
        const key = `${match.completedAt}_${match.matchId}`;
        const playerIds = new Set();
        const collect = (team) => {
            if (!team) return;
            for (const { username } of team) {
                const p = players[username];
                if (p?.userId) playerIds.add(p.userId);
            }
        };
        collect(match.teamA);
        collect(match.teamB);

        matchPayloads[key] = {
            match_key: key,
            match_id: match.matchId,
            match_type: match.matchType,
            team_a: match.teamA,
            team_b: match.teamB,
            team_a_score: match.teamAScore,
            team_b_score: match.teamBScore,
            completed_at: new Date(match.completedAt).toISOString(),
            players: Array.from(playerIds, id => ({ directus_users_id: id }))
        };
    }

    const processTeam = (team, key) => {
        if (!team) return;
        for (const { username } of team) {
            const player = players[username];
            if (!player?.userId) continue;
            if (!player.completed_matches) {
                player.completed_matches = [];
                result.push(player);
            }
            player.completed_matches.push(matchPayloads[key]);
        }
    };

    for (const match of completedMatches) {
        const key = `${match.completedAt}_${match.matchId}`;
        processTeam(match.teamA, key);
        processTeam(match.teamB, key);
    }

    return result;
};

module.exports = async function(data) {
    const trigger = data.$trigger;

    // 1. STRUCTURAL GUARD
    // Ensure the payload has the basic required structure
    if (!trigger || !trigger.body || !trigger.headers) {
        throw new Error("Validation Failed: Malformed webhook structure.");
    }

    // 2. SECURITY GUARD (Crucial)
    // Validate the Xendit Callback Token to ensure this request isn't spoofed.
    // Replace the hardcoded string with your actual token from the Xendit Dashboard, 
    // or better yet, store it in Directus Environment Variables.
    const expectedToken = data.read_payment_settings[0].webhook_verification_token;
    const incomingToken = trigger.headers['x-callback-token'];

    if (incomingToken !== expectedToken) {
        throw new Error("Security Alert: Invalid Xendit Callback Token.");
    }

    // 3. BUSINESS LOGIC GUARD
    // Ensure we are only processing successful payments
    if (trigger.body.status !== "PAID") {
        throw new Error(`Ignored Webhook: Invoice status is '${trigger.body.status}', expected 'PAID'.`);
    }

    // 4. DATA INTEGRITY GUARD
    // Ensure the required fields you need for your database exist
    if (!trigger.body.external_id || !trigger.body.paid_amount) {
        throw new Error("Validation Failed: Missing required fields (external_id or paid_amount).");
    }

    // If all guards pass, return the sanitized data for the next Flow operations
    return {
        dateNow: new Date(),
        isValid: true,
        referenceId: trigger.body.external_id,
        amount: trigger.body.paid_amount,
        paymentMethod: trigger.body.payment_method,
        timestamp: trigger.body.paid_at
    };
};
